.page-header {
  background: linear-gradient(135deg, var(--primary) 0%, var(--secondary) 100%);
  color: white;
  padding: 2rem 1rem;
  margin-bottom: 2rem;
  border-radius: 8px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}

.page-header h1 {
  margin: 0;
  font-size: 2rem;
  font-weight: 600;
}

.page-header .subtitle {
  margin: 0.5rem 0 0 0;
  opacity: 0.9;
  font-size: 1rem;
}

/* Content Area */
.content-area {
  background: white;
  padding: 2rem 1rem;
  border-radius: 8px;
  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.08);
}

/* Data Table */
.data-table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 1rem;
}

.data-table thead {
  background: #f8f9fa;
  border-bottom: 2px solid var(--primary);
}

.data-table th {
  padding: 1rem;
  text-align: left;
  font-weight: 600;
  color: var(--text-secondary);
}

.data-table td {
  padding: 0.875rem 1rem;
  border-bottom: 1px solid #e9ecef;
  color: var(--text-color);
}

.data-table tbody tr:hover {
  background: #f8f9fa;
}

/* Details Card */
.details-card {
  background: white;
  padding: 2rem;
  border-left: 4px solid var(--primary);
  border-radius: 4px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

.details-card h2 {
  color: var(--primary);
  margin-bottom: 1.5rem;
  font-size: 1.75rem;
}

.detail-row {
  display: flex;
  justify-content: space-between;
  padding: 1rem 0;
  border-bottom: 1px solid #e9ecef;
}

.detail-row:last-of-type {
  border-bottom: none;
}

.detail-row label {
  font-weight: 600;
  color: var(--text-muted);
  min-width: 200px;
}

.detail-row span {
  color: var(--text-color);
  text-align: right;
  flex: 1;
}

/* Buttons */
.btn-details, .btn-card, .btn-back {
  display: inline-block;
  padding: 0.5rem 1rem;
  background: var(--primary);
  color: white;
  text-decoration: none;
  border-radius: 4px;
  border: none;
  cursor: pointer;
  font-size: 0.9rem;
  transition: all 0.3s ease;
}

.btn-details:hover, .btn-card:hover, .btn-back:hover {
  background: #3a9840;
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(77, 190, 85, 0.3);
}

.action-buttons {
  margin-top: 2rem;
  text-align: center;
}

/* Dashboard */
.dashboard {
  background: linear-gradient(135deg, #f8f9fa 0%, #ffffff 100%);
}

.dashboard-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 1.5rem;
  margin-top: 2rem;
}

.dashboard-card {
  background: white;
  padding: 2rem;
  border-radius: 8px;
  border-top: 4px solid var(--primary);
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
  text-align: center;
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.dashboard-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 8px 16px rgba(77, 190, 85, 0.15);
}

.dashboard-card h3 {
  color: var(--text-muted);
  margin: 0 0 1rem 0;
  font-size: 1.1rem;
}

.stat-number {
  font-size: 2.5rem;
  font-weight: 700;
  color: var(--primary);
  margin: 1rem 0;
}

.btn-card {
  margin-top: 1rem;
  display: block;
  padding: 0.75rem 1.5rem;
  background: var(--secondary);
  color: #1a1a1a;
}

.btn-card:hover {
  background: #68d97f;
  color: #1a1a1a;
}

/* Breadcrumbs */
.breadcrumb-link {
  color: var(--primary);
  text-decoration: none;
  font-weight: 500;
  transition: color 0.2s ease;
}

.breadcrumb-link:hover {
  color: #3a9840;
  text-decoration: underline;
}

.breadcrumb-sep {
  color: var(--text-muted);
  margin: 0 0.5rem;
}

.breadcrumb-current {
  color: var(--text-color);
}

/* Responsive */
@media (max-width: 768px) {
  .page-header {
    padding: 1.5rem 0.75rem;
  }

  .page-header h1 {
    font-size: 1.5rem;
  }

  .content-area {
    padding: 1.5rem 0.75rem;
  }

  .data-table {
    font-size: 0.85rem;
  }

  .data-table th, .data-table td {
    padding: 0.75rem 0.5rem;
  }

  .details-card {
    padding: 1.5rem;
  }

  .detail-row {
    flex-direction: column;
    align-items: flex-start;
  }

  .detail-row label {
    margin-bottom: 0.5rem;
  }

  .detail-row span {
    text-align: left;
  }

  .dashboard-grid {
    grid-template-columns: 1fr;
  }

  .dashboard-card {
    padding: 1.5rem;
  }
}

